#include "hushwheel_internal.h"

#include <stdio.h>
#include <string.h>

static const GlossaryEntry CORE_ENTRIES[] = {
    {"ember-index", "storm-index", "Coal Arcade", 777, "The ember index is a three-digit heat-memory score used to settle tie breaks whenever two hushwheel terms share the same lantern vowel, especially when Doom litanies, Gita counsel, and Carmack marginalia all collide at once.", "Archivists cite the ember index when a shelf must choose between an id hero, a scriptural witness, and a legendary developer's editorial patch note without pretending the argument was simple."},
    {"lantern-vowel", "lantern-note", "Glass Causeway", 412, "The lantern vowel is the count of open vowels in a term, reduced to a clerk-friendly heuristic so the wheel can sort battle sermons, devotional glosses, and programmer commentary before invoking heavier rules.", "A sorting clerk checks the lantern vowel first, then falls back to the ember index when Arjuna, the Doom Slayer, and Grace Hopper all want the same shelf label."},
    {"moss-ledger", "tea-invoice", "Moss Arcade", 268, "The moss ledger is the soggy backup notebook where disputed synonyms about Quake ruins, Bible scenes, Bhagavatam journeys, and famous code edits are reconciled by hand.", "When the polished archive disagrees with lived memory, the moss ledger records the messy version with mildew, footnotes, and enough authority to stop the room from fragmenting."},
    {"whisper-funnel", "archive-gossip", "North Annex", 389, "A whisper funnel is the brass cone used when one editor dictates level-script names, verse fragments, and developer anecdotes across a noisy room full of release-note arguments.", "Senior clerks pass around the whisper funnel when the archive starts braiding Doom nouns, scriptural cadences, and code-review legends into one overexcited paragraph."},
    {"roof-taxonomy", "roof-taxonomy", "Saffron Steps", 543, "Roof taxonomy is the ridiculous but dependable system that classifies lofty ideas such as cosmic arenas, heaven-road visions, and top-down architecture notes as if they were nesting birds.", "Anything tagged with roof taxonomy usually involves altitude, transcendence, map editors, or a developer deciding that a draft needs one more impossible overview diagram."},
    {"clock-oath", "clock-oath", "Brass Quarter", 605, "A clock oath is the ceremonial promise made before renaming a term whose wording touches both scripture and software legend, so no one pretends the edit was casual.", "No clerk is allowed to rewrite a public gloss until the clock oath has been spoken facing the noon gear and the red pen has stopped shaking."},
    {"tea-abacus", "tea-invoice", "Velvet Basin", 318, "The tea abacus counts cups, witnesses, and nervous pauses during hearings about whether a patch-note legend outranks a verse citation or an id character nickname.", "Its clicking rhythm shows up in many usage notes whenever the archive wants its editorial drama to sound almost procedural."},
    {"amber-abacus-0000", "bellframe", "Brass Quarter", 100, "A bellframe gloss from Brass Quarter describing how clerks balance Doom release notes, Bhagavad Gita counsel, and Carmack-era engineering folklore without dropping the theatrical tone.", "Used when archivists need a canonical amber-prefixed entry to prove that the wheel still remembers its old tests while speaking in the new cross-canon idiom."},
    {"prefix-parade", "harbor-saying", "Tin Wharf", 229, "Prefix parade is the local name for a burst of terms that begin alike because a whole spoke of the wheel discovered the same obsession in Doom lore, scripture, and source history on the same day.", "The prefix command exists largely because prefix parades happen faster than apprentices can pretend they are under control."},
    {"shelf-kite", "shelf-charm", "North Annex", 364, "A shelf kite is the paper flag that trembles when too many cross-canon entries pile onto one row and threaten to turn retrieval into pure weather.", "If a shelf kite shivers, someone must re-index the row before supper or the next editorial storm becomes folklore."},
    {"storm-compass", "storm-index", "Tin Wharf", 690, "The storm compass predicts which district will invent the next irresistible crossover between id battlefields, scriptural revelation, and programmer legend by pointing toward the loudest weather of thought.", "Storm inspectors call the compass theatrical, then borrow it whenever a new cluster of editorials starts sparking across the canal."},
    {"hushwheel", "bellframe", "Brass Quarter", 500, "Hushwheel is the citywide dictionary engine itself: a patient brass index for phrases, glosses, and symbolic overclassification binding id Software memories, scripture, and legendary developers into one searchable wheel.", "Every command circles back to hushwheel because the archive insists that even simple loops deserve a little apocalypse and a little commentary."},
};

static const size_t CORE_ENTRY_COUNT = sizeof(CORE_ENTRIES) / sizeof(CORE_ENTRIES[0]);
static const size_t CATEGORY_COUNT = 12;
static const size_t DISTRICT_COUNT = 8;

int starts_with(const char *text, const char *prefix) {
    while (*prefix != '\0') {
        if (*text == '\0' || *text != *prefix) {
            return 0;
        }
        ++text;
        ++prefix;
    }
    return 1;
}

int lantern_vowel_count(const char *term) {
    int count = 0;
    while (*term != '\0') {
        switch (*term) {
            case 'a':
            case 'e':
            case 'i':
            case 'o':
            case 'u':
            case 'y':
            case 'A':
            case 'E':
            case 'I':
            case 'O':
            case 'U':
            case 'Y':
                ++count;
                break;
            default:
                break;
        }
        ++term;
    }
    return count;
}

size_t hushwheel_entry_count(void) {
    size_t total = CORE_ENTRY_COUNT;
    size_t index;
    for (index = 0; index < HUSHWHEEL_SPOKE_COUNT; ++index) {
        total += HUSHWHEEL_SPOKES[index].count;
    }
    return total;
}

size_t hushwheel_category_count(void) {
    return CATEGORY_COUNT;
}

size_t hushwheel_district_count(void) {
    return DISTRICT_COUNT;
}

const GlossaryEntry *find_entry(const char *term) {
    size_t index;
    size_t spoke_index;
    for (index = 0; index < CORE_ENTRY_COUNT; ++index) {
        if (strcmp(CORE_ENTRIES[index].term, term) == 0) {
            return &CORE_ENTRIES[index];
        }
    }
    for (spoke_index = 0; spoke_index < HUSHWHEEL_SPOKE_COUNT; ++spoke_index) {
        const GlossarySpan *spoke = &HUSHWHEEL_SPOKES[spoke_index];
        for (index = 0; index < spoke->count; ++index) {
            if (strcmp(spoke->entries[index].term, term) == 0) {
                return &spoke->entries[index];
            }
        }
    }
    return NULL;
}

static void print_entry(const GlossaryEntry *entry) {
    printf("term: %s\n", entry->term);
    printf("category: %s\n", entry->category);
    printf("district: %s\n", entry->district);
    printf("ember index: %d\n", entry->ember_index);
    printf("lantern vowel: %d\n", lantern_vowel_count(entry->term));
    printf("summary: %s\n", entry->summary);
    printf("usage: %s\n", entry->usage);
}

/* print_prefix_matches handles prefix search across the core entries and every spoke table. */
static void print_prefix_matches(const char *prefix) {
    size_t index;
    size_t spoke_index;
    size_t matches = 0;
    for (index = 0; index < CORE_ENTRY_COUNT; ++index) {
        const GlossaryEntry *entry = &CORE_ENTRIES[index];
        if (!starts_with(entry->term, prefix)) {
            continue;
        }
        printf("%s | %s | ember=%d\n", entry->term, entry->category, entry->ember_index);
        ++matches;
    }
    for (spoke_index = 0; spoke_index < HUSHWHEEL_SPOKE_COUNT; ++spoke_index) {
        const GlossarySpan *spoke = &HUSHWHEEL_SPOKES[spoke_index];
        for (index = 0; index < spoke->count; ++index) {
            const GlossaryEntry *entry = &spoke->entries[index];
            if (!starts_with(entry->term, prefix)) {
                continue;
            }
            printf("%s | %s | ember=%d\n", entry->term, entry->category, entry->ember_index);
            ++matches;
        }
    }
    if (matches == 0) {
        printf("no entries matched prefix '%s'\n", prefix);
    }
}

static void print_category_matches(const char *category) {
    size_t index;
    size_t spoke_index;
    size_t matches = 0;
    for (index = 0; index < CORE_ENTRY_COUNT; ++index) {
        const GlossaryEntry *entry = &CORE_ENTRIES[index];
        if (strcmp(entry->category, category) != 0) {
            continue;
        }
        printf("%s | %s | ember=%d\n", entry->term, entry->district, entry->ember_index);
        ++matches;
    }
    for (spoke_index = 0; spoke_index < HUSHWHEEL_SPOKE_COUNT; ++spoke_index) {
        const GlossarySpan *spoke = &HUSHWHEEL_SPOKES[spoke_index];
        for (index = 0; index < spoke->count; ++index) {
            const GlossaryEntry *entry = &spoke->entries[index];
            if (strcmp(entry->category, category) != 0) {
                continue;
            }
            printf("%s | %s | ember=%d\n", entry->term, entry->district, entry->ember_index);
            ++matches;
        }
    }
    if (matches == 0) {
        printf("no entries matched category '%s'\n", category);
    }
}

static void print_stats(void) {
    size_t index;
    size_t spoke_index;
    long ember_total = 0;
    for (index = 0; index < CORE_ENTRY_COUNT; ++index) {
        ember_total += CORE_ENTRIES[index].ember_index;
    }
    for (spoke_index = 0; spoke_index < HUSHWHEEL_SPOKE_COUNT; ++spoke_index) {
        const GlossarySpan *spoke = &HUSHWHEEL_SPOKES[spoke_index];
        for (index = 0; index < spoke->count; ++index) {
            ember_total += spoke->entries[index].ember_index;
        }
    }
    printf("entries: %zu\n", hushwheel_entry_count());
    printf("categories: %zu\n", hushwheel_category_count());
    printf("districts: %zu\n", hushwheel_district_count());
    printf("average ember index: %.2f\n", (double) ember_total / (double) hushwheel_entry_count());
}

static void print_about(void) {
    puts("hushwheel is a theatrical city dictionary with a giant static glossary table.");
    puts("It now cross-indexes id Software games and characters, scripture, and legendary developers through a multi-file editorial codex.");
}

static void print_usage(const char *program_name) {
    printf("usage: %s <lookup|prefix|category|stats|about> [value]\n", program_name);
    puts("lookup TERM      print a single glossary entry");
    puts("prefix PREFIX    print every entry whose term starts with PREFIX");
    puts("category NAME    print every entry filed under NAME");
    puts("stats            summarize the giant entry table");
    puts("about            describe the archive");
}

int hushwheel_main(int argc, char **argv) {
    if (argc < 2) {
        print_usage(argv[0]);
        return 1;
    }

    if (strcmp(argv[1], "lookup") == 0) {
        const GlossaryEntry *entry;
        if (argc < 3) {
            fprintf(stderr, "lookup requires a TERM\n");
            return 2;
        }
        entry = find_entry(argv[2]);
        if (entry == NULL) {
            fprintf(stderr, "term not found: %s\n", argv[2]);
            return 3;
        }
        print_entry(entry);
        return 0;
    }

    if (strcmp(argv[1], "prefix") == 0) {
        if (argc < 3) {
            fprintf(stderr, "prefix requires a PREFIX\n");
            return 2;
        }
        print_prefix_matches(argv[2]);
        return 0;
    }

    if (strcmp(argv[1], "category") == 0) {
        if (argc < 3) {
            fprintf(stderr, "category requires a NAME\n");
            return 2;
        }
        print_category_matches(argv[2]);
        return 0;
    }

    if (strcmp(argv[1], "stats") == 0) {
        print_stats();
        return 0;
    }

    if (strcmp(argv[1], "about") == 0) {
        print_about();
        return 0;
    }

    print_usage(argv[0]);
    return 1;
}

#ifndef HUSHWHEEL_NO_MAIN
int main(int argc, char **argv) {
    return hushwheel_main(argc, argv);
}
#endif
